// Busca sessões marcadas como REALIZADA no Redis
// O fluxo principal ou a equipe da clínica marca a sessão como REALIZADA
// salvando uma chave no Redis: sessao_realizada_{event_id}
// com os dados do lead e da sessão

// IMPLEMENTAR: usar nó Redis LIST ou buscar chaves com prefixo 'sessao_realizada_*'
// Por ora retorna mock para desenvolvimento

const agora = new Date();
const umaHoraAtras = new Date(agora - 60 * 60 * 1000);

// Simulação — em produção buscar do Redis
const sessoesMock = [
  {
    event_id: 'evt_exemplo_001',
    numero_lead: '5565999990001',
    nome_lead: 'Maria Silva',
    area_sessao: 'virilha completa',
    numero_sessao: '3ª sessão',
    total_sessoes: 10,
    sessoes_restantes: 7,
    realizada_em: umaHoraAtras.toISOString(),
    numero_receptor: '553171556818',
    unidade_nome: 'Crystal Laser Contagem',
    cidade: 'Contagem',
    instancia: 'crystal-contagem'
  }
];

// Filtra sessões realizadas há entre 55 e 65 minutos (janela de 1h)
const elegiveis = sessoesMock.filter(s => {
  const realizadaEm = new Date(s.realizada_em);
  const diffMin = (agora - realizadaEm) / (1000 * 60);
  return diffMin >= 55 && diffMin <= 65;
});

if (elegiveis.length === 0) {
  return [{ json: { sem_sessoes: true } }];
}

return elegiveis.map(s => ({
  json: {
    ...s,
    evolution_url: `http://31.97.93.103:8080/message/sendText/${s.instancia}`,
    evolution_apikey: 'iara-evo-key-2026'
  }
}));

const dados = $input.first().json;
const fs = require('fs');

let systemPrompt = fs.readFileSync(
  '/home/iara/clients/Crystal-Laser/agents/nps_system_prompt.md',
  'utf8'
);

systemPrompt = systemPrompt
  .replaceAll('{{unidade_nome}}', dados.unidade_nome)
  .replaceAll('{{cidade}}', dados.cidade)
  .replaceAll('{{nome_lead}}', dados.nome_lead || '')
  .replaceAll('{{area_sessao}}', dados.area_sessao || '')
  .replaceAll('{{numero_sessao}}', dados.numero_sessao || '1ª sessão')
  .replaceAll('{{total_sessoes}}', String(dados.total_sessoes || 10))
  .replaceAll('{{sessoes_restantes}}', String(dados.sessoes_restantes || 9))
  .replaceAll('{{nota_nps}}', '');

const instrucao = 'Gere APENAS a mensagem inicial de NPS para enviar ao cliente após a sessão. Nada mais além da mensagem.';

return [{
  json: {
    ...dados,
    system_prompt_final: systemPrompt,
    messages_payload: [{ role: 'user', content: instrucao }]
  }
}];

const dados = $input.first().json;

// Marca NPS como enviado e aguarda resposta do lead
// O fluxo principal detecta a resposta via webhook e processa
const chave = `nps_aguardando_${dados.numero_lead}`;

return [{
  json: {
    redis_chave: chave,
    redis_valor: JSON.stringify({
      event_id: dados.event_id,
      numero_lead: dados.numero_lead,
      nome_lead: dados.nome_lead,
      area_sessao: dados.area_sessao,
      numero_sessao: dados.numero_sessao,
      total_sessoes: dados.total_sessoes,
      sessoes_restantes: dados.sessoes_restantes,
      unidade_nome: dados.unidade_nome,
      numero_receptor: dados.numero_receptor,
      instancia: dados.instancia,
      evolution_url: dados.evolution_url,
      nps_enviado_em: new Date().toISOString(),
      estagio: 'AGUARDANDO_NOTA'
    }),
    redis_ttl: 259200
  }
}];

const dados = $input.first().json;
const mensagem = dados.mensagem || '';

// Extrai nota da mensagem (1 a 5)
const notaMatch = mensagem.match(/[1-5]/);
const nota = notaMatch ? parseInt(notaMatch[0]) : null;

if (!nota) {
  return [{ json: { ...dados, nota: null, acao: 'AGUARDAR_NOTA_VALIDA' } }];
}

let acao = 'NPS_NEUTRO';
if (nota >= 4) acao = 'NPS_POSITIVO';
else if (nota <= 2) acao = 'NPS_NEGATIVO';

return [{ json: { ...dados, nota, acao } }];

